+import { _addIssue, _getStandardProps } from '../../utils/index.ts';
+
+/**
+ * Recursive placeholder schema interface.
+ */
+export interface RecurSchema extends BaseSchema<RecurSchema, RecurSchema, never> {
+  /**
+   * The schema type.
+   */
+  readonly type: 'recur';
+  /**
+   * The schema reference.
+   */
+  readonly reference: typeof recursive;
+  /**
+   * The expected property.
+   */
+  readonly expects: 'unknown';
+}
+
+/**
+ * Replaces recursive placeholders in a type with a recursive schema type.
+ */
+type ResolveRecur<TValue, TSchema> = TValue extends RecurSchema
+  ? TSchema
+  : TValue extends Map<infer TKey, infer TMapValue>
+    ? Map<ResolveRecur<TKey, TSchema>, ResolveRecur<TMapValue, TSchema>>
+    : TValue extends Set<infer TSetValue>
+      ? Set<ResolveRecur<TSetValue, TSchema>>
+      : TValue extends readonly (infer TArrayValue)[]
+        ? ResolveRecur<TArrayValue, TSchema>[]
+        : TValue extends object
+          ? { [TKey in keyof TValue]: ResolveRecur<TValue[TKey], TSchema> }
+          : TValue;
+
+/**
+ * Tests whether a type contains a recursive placeholder.
+ *
+ * @internal
+ */
+export type ContainsRecur<TValue> = TValue extends RecurSchema
+  ? true
+  : TValue extends Map<infer TKey, infer TMapValue>
+    ? true extends ContainsRecur<TKey> | ContainsRecur<TMapValue>
+      ? true
+      : false
+    : TValue extends Set<infer TSetValue>
+      ? ContainsRecur<TSetValue>
+      : TValue extends readonly (infer TArrayValue)[]
+        ? ContainsRecur<TArrayValue>
+        : TValue extends object
+          ? true extends {
+              [TKey in keyof TValue]: ContainsRecur<TValue[TKey]>;
+            }[keyof TValue]
+            ? true
+            : false
+          : false;
+
+/**
+ * Recursive schema interface.
+ */
+export interface RecursiveSchema<
+  TWrapped extends BaseSchema<unknown, unknown, BaseIssue<unknown>>,
+> extends BaseSchema<
+    ResolveRecur<InferInput<TWrapped>, RecursiveSchema<TWrapped>>,
+    ResolveRecur<InferOutput<TWrapped>, RecursiveSchema<TWrapped>>,
+    InferIssue<TWrapped>
+  > {
+  /**
+   * The schema type.
+   */
+  readonly type: 'recursive';
+  /**
+   * The schema reference.
+   */
+  readonly reference: typeof recursive;
+  /**
+   * The wrapped schema.
+   */
+  readonly wrapped: TWrapped;
+}
+
+/**
+ * Recursive schema async interface.
+ */
+export interface RecursiveSchemaAsync<
+  TWrapped extends
+    | BaseSchema<unknown, unknown, BaseIssue<unknown>>
+    | BaseSchemaAsync<unknown, unknown, BaseIssue<unknown>>,
+> extends BaseSchemaAsync<
+    ResolveRecur<InferInput<TWrapped>, RecursiveSchemaAsync<TWrapped>>,
+    ResolveRecur<InferOutput<TWrapped>, RecursiveSchemaAsync<TWrapped>>,
+    InferIssue<TWrapped>
+  > {
+  /**
+   * The schema type.
+   */
+  readonly type: 'recursive';
+  /**
+   * The schema reference.
+   */
+  readonly reference: typeof recursive | typeof recursiveAsync;
+  /**
+   * The wrapped schema.
+   */
+  readonly wrapped: TWrapped;
+}
+
+/**
+ * Placeholder for a self reference in a recursive schema.
+ */
+export const Recur: RecurSchema = {
+  kind: 'schema',
+  type: 'recur',
+  reference: recursive,
+  expects: 'unknown',
+  async: false,
+  get '~standard'() {
+    return _getStandardProps(this);
+  },
+  '~run'(dataset, config) {
+    _addIssue(this, 'type', dataset, config);
+    return dataset as OutputDataset<RecurSchema, never>;
+  },
+};
+
+/**
+ * Creates a copy of a schema graph with recursive placeholders resolved.
+ */
+function resolveRecur<TValue>(value: TValue, recursiveSchema: unknown): TValue {
+  const references = new Map<object, unknown>();
+
+  const resolve = (current: unknown): unknown => {
+    if (current === Recur) {
+      return recursiveSchema;
+    }
+    if (!current || typeof current !== 'object') {
+      return current;
+    }
+    const prototype = Object.getPrototypeOf(current);
+    if (prototype !== Object.prototype && prototype !== null && !Array.isArray(current)) {
+      return current;
+    }
+    const existing = references.get(current);
+    if (existing) {
+      return existing;
+    }
+    const copy: object = Array.isArray(current)
+      ? []
+      : Object.create(prototype);
+    references.set(current, copy);
+    for (const key of Reflect.ownKeys(current)) {
+      const descriptor = Object.getOwnPropertyDescriptor(current, key)!;
+      if ('value' in descriptor) {
+        descriptor.value = resolve(descriptor.value);
+      }
+      Object.defineProperty(copy, key, descriptor);
+    }
+    return copy;
+  };
+
+  return resolve(value) as TValue;
+}
+
+/**
+ * Wraps a schema and resolves its recursive placeholders.
+ *
+ * @param wrapped The schema to wrap.
+ *
+ * @returns A recursive schema.
+ */
+// @__NO_SIDE_EFFECTS__
+export function recursive<
+  const TWrapped extends BaseSchema<unknown, unknown, BaseIssue<unknown>>,
+>(wrapped: TWrapped): RecursiveSchema<TWrapped> {
+  const schema = {
+    kind: 'schema' as const,
+    type: 'recursive' as const,
+    reference: recursive,
+    expects: wrapped.expects,
+    async: false as const,
+    wrapped: undefined as unknown as TWrapped,
+    get '~standard'() {
+      return _getStandardProps(this);
+    },
+    '~run'(dataset: UnknownDataset, config: Config<BaseIssue<unknown>>) {
+      return this.wrapped['~run'](dataset, config);
+    },
+  } satisfies Omit<RecursiveSchema<TWrapped>, 'wrapped'> & {
+    wrapped: TWrapped;
+  };
+  schema.wrapped = resolveRecur(wrapped, schema);
+  return schema;
+}
+
+/**
+ * Wraps a schema and resolves its recursive placeholders asynchronously.
+ *
+ * @param wrapped The schema to wrap.
+ *
+ * @returns A recursive schema.
+ */
+// @__NO_SIDE_EFFECTS__
+export function recursiveAsync<
+  const TWrapped extends
+    | BaseSchema<unknown, unknown, BaseIssue<unknown>>
+    | BaseSchemaAsync<unknown, unknown, BaseIssue<unknown>>,
+>(wrapped: TWrapped): RecursiveSchemaAsync<TWrapped> {
+  const schema = {
+    kind: 'schema' as const,
+    type: 'recursive' as const,
+    reference: recursiveAsync,
+    expects: wrapped.expects,
+    async: true as const,
+    wrapped: undefined as unknown as TWrapped,
+    get '~standard'() {
+      return _getStandardProps(this);
+    },
+    async '~run'(dataset: UnknownDataset, config: Config<BaseIssue<unknown>>) {
+      return this.wrapped['~run'](dataset, config);
+    },
+  } satisfies Omit<RecursiveSchemaAsync<TWrapped>, 'wrapped'> & {
+    wrapped: TWrapped;
+  };
+  schema.wrapped = resolveRecur(wrapped, schema);
+  return schema;
+}
