+    const arraySchema = recursive(object({ children: array(Recur) }));
+    const recordSchema = recursive(object({ children: record(string(), Recur) }));
+    const mapSchema = recursive(object({ children: map(string(), Recur) }));
+    const setSchema = recursive(object({ children: set(Recur) }));
