+ * Recursive schema interface.
+ */
+export interface RecursiveSchema<
+  TWrapped extends BaseSchema<unknown, unknown, BaseIssue<unknown>>,
+> extends BaseSchema<
+    ResolveRecur<InferInput<TWrapped>, RecursiveSchema<TWrapped>>,
+    ResolveRecur<InferOutput<TWrapped>, RecursiveSchema<TWrapped>>,
+    InferIssue<TWrapped>
+  > {
