+  type: 'recur',
+  reference: recursive,
+  expects: 'unknown',
+  async: false,
+  get '~standard'() {
+    return _getStandardProps(this);
+  },
+  '~run'(dataset, config) {
+    _addIssue(this, 'type', dataset, config);
+    return dataset as OutputDataset<RecurSchema, never>;
+  },
+};
+
+/**
+ * Creates a copy of a schema graph with recursive placeholders resolved.
+ */
+function resolveRecur<TValue>(value: TValue, recursiveSchema: unknown): TValue {
+  const references = new Map<object, unknown>();
+
+  const resolve = (current: unknown): unknown => {
+    if (current === Recur) {
+      return recursiveSchema;
+    }
+    if (!current || typeof current !== 'object') {
+      return current;
+    }
+    const prototype = Object.getPrototypeOf(current);
+    if (prototype !== Object.prototype && prototype !== null && !Array.isArray(current)) {
+      return current;
+    }
+    const existing = references.get(current);
+    if (existing) {
+      return existing;
+    }
+    const copy: object = Array.isArray(current)
+      ? []
+      : Object.create(prototype);
+    references.set(current, copy);
+    for (const key of Reflect.ownKeys(current)) {
+      const descriptor = Object.getOwnPropertyDescriptor(current, key)!;
+      if ('value' in descriptor) {
+        descriptor.value = resolve(descriptor.value);
+      }
+      Object.defineProperty(copy, key, descriptor);
+    }
+    return copy;
+  };
+
+  return resolve(value) as TValue;
+}
