+/**
+ * Wraps a schema and resolves its recursive placeholders.
+ *
+ * @param wrapped The schema to wrap.
+ *
+ * @returns A recursive schema.
+ */
+// @__NO_SIDE_EFFECTS__
+export function recursive<
+  const TWrapped extends BaseSchema<unknown, unknown, BaseIssue<unknown>>,
+>(wrapped: TWrapped): RecursiveSchema<TWrapped> {
+  const schema = {
+    kind: 'schema' as const,
+    type: 'recursive' as const,
+    reference: recursive,
+    expects: wrapped.expects,
+    async: false as const,
+    wrapped: undefined as unknown as TWrapped,
+    get '~standard'() {
+      return _getStandardProps(this);
+    },
+    '~run'(dataset: UnknownDataset, config: Config<BaseIssue<unknown>>) {
+      return this.wrapped['~run'](dataset, config);
+    },
+  } satisfies Omit<RecursiveSchema<TWrapped>, 'wrapped'> & {
+    wrapped: TWrapped;
+  };
+  schema.wrapped = resolveRecur(wrapped, schema);
+  return schema;
+}
