+      return this.wrapped['~run'](dataset, config);
+    },
+  } satisfies Omit<RecursiveSchemaAsync<TWrapped>, 'wrapped'> & {
+    wrapped: TWrapped;
+  };
+  schema.wrapped = resolveRecur(wrapped, schema);
+  return schema;
+}
